-- ----------------------------
-- Table structure for collect
-- ----------------------------
DROP TABLE IF EXISTS `collect`;
CREATE TABLE `collect`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '收藏ID',
  `user_id` bigint NOT NULL COMMENT '用户ID，关联user_info.id',
  `target_id` bigint NOT NULL COMMENT '收藏目标ID：景点ID/美食ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型：1-景点，2-美食',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_target`(`user_id` ASC, `target_id` ASC, `target_type` ASC) USING BTREE COMMENT '用户对同一目标仅能收藏一次',
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '收藏表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of collect
-- ----------------------------

-- ----------------------------
-- Table structure for comment
-- ----------------------------
DROP TABLE IF EXISTS `comment`;
CREATE TABLE `comment`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '评论ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `target_id` bigint NOT NULL COMMENT '评论目标ID：景点ID/美食ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型：1-景点，2-美食',
  `score` tinyint NOT NULL COMMENT '评论评分（1-5星）',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '评论内容',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '评论标签，多个用逗号分隔',
  `imgs` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '评论图片，多个用逗号分隔',
  `like_count` int NULL DEFAULT 0 COMMENT '评论点赞数',
  `audit_admin_id` bigint NULL DEFAULT NULL COMMENT '审核人ID（关联admin.id）',
  `audit_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  `status` tinyint NULL DEFAULT 1 COMMENT '审核状态：1-待审核，2-已通过，3-已拒绝',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_target`(`target_id` ASC, `target_type` ASC) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_delete_status`(`delete_time` ASC, `status` ASC) USING BTREE,
  INDEX `idx_audit_admin_id`(`audit_admin_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '评论表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of comment
-- ----------------------------

-- ----------------------------
-- Table structure for comment_reply
-- ----------------------------
DROP TABLE IF EXISTS `comment_reply`;
CREATE TABLE `comment_reply`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '回复ID',
  `comment_id` bigint NOT NULL COMMENT '原评论ID，关联comment.id',
  `user_id` bigint NOT NULL COMMENT '回复用户ID',
  `to_user_id` bigint NOT NULL COMMENT '被回复用户ID',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '回复内容',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  `status` tinyint NULL DEFAULT 1 COMMENT '状态：1-正常，2-已屏蔽',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_comment_id`(`comment_id` ASC) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_delete_status`(`delete_time` ASC, `status` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '评论回复表（一级回复）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of comment_reply
-- ----------------------------

-- ----------------------------
-- Table structure for feedback
-- ----------------------------
DROP TABLE IF EXISTS `feedback`;
CREATE TABLE `feedback`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '反馈ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `type` tinyint NOT NULL COMMENT '反馈类型：1-景点添加，2-美食添加，3-Bug反馈，4-投诉，5-功能建议，6-其他',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '反馈内容',
  `contact` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联系方式（手机号/微信）',
  `imgs` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '反馈图片，多个用逗号分隔',
  `handle_admin_id` bigint NULL DEFAULT NULL COMMENT '处理人ID（关联admin.id）',
  `handle_result` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '处理结果',
  `handle_time` datetime NULL DEFAULT NULL COMMENT '处理时间',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  `status` tinyint NULL DEFAULT 0 COMMENT '处理状态：0-待处理，1-已处理，2-已驳回',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  INDEX `idx_delete_status`(`delete_time` ASC, `status` ASC) USING BTREE,
  INDEX `idx_handle_admin_id`(`handle_admin_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '意见反馈表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of feedback
-- ----------------------------

-- ----------------------------
-- Table structure for food
-- ----------------------------
DROP TABLE IF EXISTS `food`;
CREATE TABLE `food`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '美食/商户ID，主键',
  `name_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '美食/商户名称（中文）',
  `name_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '美食/商户名称（英文）',
  `desc_cn` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '美食介绍（中文）',
  `desc_en` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '美食介绍（英文）',
  `merchant_name_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '商户名称（中文）',
  `merchant_name_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '商户名称（英文）',
  `signature_dish_cn` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '招牌菜（中文）',
  `signature_dish_en` varchar(800) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '招牌菜（英文）',
  `per_capita` decimal(10, 2) NOT NULL COMMENT '人均消费（数值）',
  `per_capita_cn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '人均消费（中文，含单位）',
  `per_capita_en` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '人均消费（英文，含单位）',
  `business_time_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '营业时长（中文）',
  `business_time_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '营业时长（英文）',
  `address_cn` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详细地址（中文）',
  `address_en` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详细地址（英文）（优化：长度从800缩至500）',
  `longitude` decimal(15, 10) NOT NULL COMMENT '经度（高德地图）',
  `latitude` decimal(15, 10) NOT NULL COMMENT '纬度（高德地图）',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联系电话',
  `park_info_cn` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '停车信息（中文）',
  `park_info_en` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '停车信息（英文）',
  `type` tinyint NOT NULL COMMENT '美食品类：1-百色特色菜，2-小吃，3-茶饮',
  `type_cn` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '美食品类名称（中文）',
  `type_en` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '美食品类名称（英文）',
  `service_type` tinyint NULL DEFAULT 0 COMMENT '服务类型：0-仅堂食，1-堂食+配送',
  `service_type_cn` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '服务类型名称（中文）',
  `service_type_en` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '服务类型名称（英文）',
  `total_score` decimal(3, 1) NULL DEFAULT 0.0 COMMENT '总评分',
  `score_count` int NULL DEFAULT 0 COMMENT '评分人数',
  `visit_count` bigint NULL DEFAULT 0 COMMENT '访问量（热度）',
  `collect_count` bigint NULL DEFAULT 0 COMMENT '收藏量（热度）',
  `cover_img` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '封面图地址',
  `imgs` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '菜品轮播图，多个用逗号分隔',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  INDEX `idx_total_score`(`total_score` ASC) USING BTREE,
  INDEX `idx_per_capita`(`per_capita` ASC) USING BTREE,
  INDEX `idx_collect_visit`(`collect_count` ASC, `visit_count` ASC) USING BTREE COMMENT '热度排序索引',
  INDEX `idx_type_per_capita`(`type` ASC, `per_capita` ASC) USING BTREE COMMENT '按类型+人均消费筛选',
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE,
  INDEX `idx_name_cn`(`name_cn` ASC) USING BTREE COMMENT '美食名称中文搜索'
) ENGINE = InnoDB AUTO_INCREMENT = 97 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '美食/商户信息表（全字段中英双语）' ROW_FORMAT = Dynamic;

