INSERT INTO `food` VALUES (63, '那坡红薯粑粑', 'Napo Sweet Potato Cakes', '那坡本土特色小吃，红薯蒸熟压泥，混合糯米粉煎制成饼，外酥里糯，香甜可口', 'Local characteristic snack in Napo, sweet potatoes steamed and mashed, mixed with glutinous rice flour and fried into cakes, crispy outside and glutinous inside, sweet and delicious', '那坡街头小吃摊（城厢店）', 'Napo Street Snack Stall (Chengxiang Branch)', '红薯粑粑', 'Sweet Potato Cakes', 4.00, '人均消费', 'Per capita consumption', '08:00-18:00', '08:00-18:00', '广西百色市那坡县城厢镇', 'Chengxiang Town, Napo County, Baise City, Guangxi', 105.8765000000, 23.4567000000, '13877776666', '无专用车位（街边可临时停）', 'No dedicated parking (temporary parking on street)', 2, '小吃', 'Snack', 0, '堂食', 'Dine-in', 45.0, 10, 850, 250, 'https://img3.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
