INSERT INTO `food` VALUES (65, '德保猪血肠', 'Debao Pork Blood Sausage', '德保壮族特色美食，糯米混合猪血灌入肠衣，煮熟后切片煎香，咸香浓郁', 'Zhuang characteristic food in Debao, glutinous rice mixed with pig blood poured into casings, cooked and sliced for frying, rich salty fragrance', '德保壮家菜馆（城关店）', 'Debao Zhuang Restaurant (Chengguan Branch)', '猪血肠', 'Pork Blood Sausage', 35.00, '人均消费', 'Per capita consumption', '09:00-21:00', '09:00-21:00', '广西百色市德保县城关镇', 'Chengguan Town, Debao County, Baise City, Guangxi', 106.4567000000, 23.7890000000, '13888881111', '店前停车位', 'Parking in front of the store', 1, '特色菜', 'Featured Dish', 0, '堂食', 'Dine-in', 48.0, 10, 980, 290, 'https://img1.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img2.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (66, '德保矮马肉火锅', 'Debao Pony Meat Hot Pot', '德保特色火锅，本地矮马肉切块，搭配八角、桂皮等香料熬汤，肉质紧实，鲜香无膻', 'Characteristic hot pot in Debao, local pony meat cut into pieces, boiled with star anise, cinnamon and other spices, firm meat, fresh and no mutton smell', '德保矮马主题餐馆（足荣店）', 'Debao Pony Theme Restaurant (Zurong Branch)', '矮马肉火锅', 'Pony Meat Hot Pot', 128.00, '人均消费', 'Per capita consumption', '10:00-22:00', '10:00-22:00', '广西百色市德保县足荣镇', 'Zurong Town, Debao County, Baise City, Guangxi', 106.5678000000, 23.8901000000, '13888882222', '大型停车场', 'Large Parking Lot', 1, '火锅', 'Hot Pot', 1, '堂食+配送', 'Dine-in + Delivery', 49.0, 10, 1150, 340, 'https://img2.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
