INSERT INTO `food` VALUES (70, '德保五色糯米饭', 'Debao Five-Color Glutinous Rice', '德保壮族特色美食，糯米用天然植物染料染成五色，蒸熟后软糯香甜，寓意吉祥', 'Zhuang characteristic food in Debao, glutinous rice dyed into five colors with natural plant dyes, steamed to be glutinous and sweet, implying auspiciousness', '德保壮家菜馆（城关店）', 'Debao Zhuang Restaurant (Chengguan Branch)', '五色糯米饭', 'Five-Color Glutinous Rice', 18.00, '人均消费', 'Per capita consumption', '09:00-20:00', '09:00-20:00', '广西百色市德保县城关镇', 'Chengguan Town, Debao County, Baise City, Guangxi', 106.4567000000, 23.7890000000, '13888886666', '店前停车位', 'Parking in front of the store', 1, '特色菜', 'Featured Dish', 0, '堂食', 'Dine-in', 47.0, 10, 980, 290, 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (71, '德保手工米粉', 'Debao Handmade Rice Noodles', '德保本土特色粉，米浆手工蒸制，薄而有韧性，搭配肉汤、叉烧，鲜香味美', 'Local characteristic noodles in Debao, rice milk handmade and steamed, thin and tough, served with meat soup and barbecued pork, fresh and delicious', '德保米粉老店（城关店）', 'Debao Old Brand Rice Noodles Shop (Chengguan Branch)', '手工米粉', 'Handmade Rice Noodles', 10.00, '人均消费', 'Per capita consumption', '06:30-14:00', '06:30-14:00', '广西百色市德保县城关镇', 'Chengguan Town, Debao County, Baise City, Guangxi', 106.4567000000, 23.7890000000, '13888887777', '街边停车位', 'Street Parking Spaces', 2, '粉面', 'Noodles', 0, '堂食', 'Dine-in', 46.0, 10, 900, 270, 'https://img3.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
