INSERT INTO `food` VALUES (76, '乐业糯米饭', 'Leye Glutinous Rice', '乐业经典早餐，糯米蒸熟后捏成团，搭配炒肉、酸菜、花生，咸香适口，饱腹感强', 'Classic breakfast in Leye, glutinous rice steamed and kneaded into balls, served with stir-fried meat, pickled vegetables and peanuts, salty and palatable, strong satiety', '乐业早餐店（同乐店）', 'Leye Breakfast Shop (Tongle Branch)', '糯米饭', 'Glutinous Rice', 8.00, '人均消费', 'Per capita consumption', '06:00-11:00', '06:00-11:00', '广西百色市乐业县同乐镇', 'Tongle Town, Leye County, Baise City, Guangxi', 106.5432000000, 24.7654000000, '13899994444', '街边停车位', 'Street Parking Spaces', 2, '早餐', 'Breakfast', 0, '堂食', 'Dine-in', 46.0, 10, 880, 260, 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
