INSERT INTO `food` VALUES (78, '乐业玉米粑粑', 'Leye Corn Cakes', '乐业本土小吃，玉米磨浆煎制成饼，外酥里糯，香甜可口，街头常见', 'Local snack in Leye, corn ground into pulp and fried into cakes, crispy outside and glutinous inside, sweet and delicious, common on the street', '乐业街头小吃摊（同乐店）', 'Leye Street Snack Stall (Tongle Branch)', '玉米粑粑', 'Corn Cakes', 4.00, '人均消费', 'Per capita consumption', '08:00-18:00', '08:00-18:00', '广西百色市乐业县同乐镇', 'Tongle Town, Leye County, Baise City, Guangxi', 106.5432000000, 24.7654000000, '13899996666', '无专用车位（街边可临时停）', 'No dedicated parking (temporary parking on street)', 2, '小吃', 'Snack', 0, '堂食', 'Dine-in', 45.0, 10, 850, 250, 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (79, '乐业酸汤鱼', 'Leye Sour Soup Fish', '乐业苗族特色菜，本地河鱼搭配自制酸汤熬煮，酸香开胃，鱼肉鲜嫩', 'Miao characteristic dish in Leye, local river fish boiled with homemade sour soup, sour and appetizing, tender fish meat', '乐业苗族菜馆（新化店）', 'Leye Miao Restaurant (Xinhua Branch)', '酸汤鱼', 'Sour Soup Fish', 78.00, '人均消费', 'Per capita consumption', '10:00-22:00', '10:00-22:00', '广西百色市乐业县新化镇', 'Xinhua Town, Leye County, Baise City, Guangxi', 106.6543000000, 24.6543000000, '13899997777', '店内停车场', 'In-store Parking Lot', 1, '特色菜', 'Featured Dish', 1, '堂食+配送', 'Dine-in + Delivery', 47.0, 10, 900, 270, 'https://img3.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
