INSERT INTO `food` VALUES (81, '凌云白毫茶', 'Lingyun Baihao Tea', '凌云地标特产，白毫茶色泽翠绿，香气清高，汤色清澈，滋味鲜爽，回甘悠长', 'Lingyun landmark specialty, Baihao tea has green color, high fragrance, clear soup color, fresh taste and long aftertaste', '凌云茶庄（泗城店）', 'Lingyun Tea House (Sicheng Branch)', '白毫茶', 'Baihao Tea', 30.00, '人均消费', 'Per capita consumption', '09:00-20:00', '09:00-20:00', '广西百色市凌云县泗城镇', 'Sicheng Town, Lingyun County, Baise City, Guangxi', 106.5678000000, 24.3456000000, '13966661111', '店内停车场', 'In-store Parking Lot', 3, '茶饮', 'Tea', 1, '堂食+配送', 'Dine-in + Delivery', 48.0, 10, 1100, 330, 'https://img1.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
