INSERT INTO `food` VALUES (91, '平果香糯粽', 'Pingguo Glutinous Rice Dumplings', '平果壮族特色粽子，糯米配五花肉、绿豆、板栗，个头饱满，粽香浓郁', 'Zhuang characteristic zongzi in Pingguo, glutinous rice with pork belly, mung beans and chestnuts, plump and rich zongzi fragrance', '平果壮家粽店（马头店）', 'Pingguo Zhuang Zongzi Shop (Matou Branch)', '五花肉香糯粽', 'Pork Belly Glutinous Rice Dumplings', 12.00, '人均消费', 'Per capita consumption', '08:00-18:00', '08:00-18:00', '广西百色市平果市马头镇城龙路', 'Chenglong Road, Matou Town, Pingguo City, Baise City, Guangxi', 107.5678000000, 23.3432000000, '13911113333', '店前停车位', 'Parking in front of the store', 2, '小吃', 'Snack', 0, '堂食', 'Dine-in', 48.0, 10, 1080, 320, 'https://img2.baidu.com/it/u=3344556677,8899001122&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=3344556677,8899001122&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (92, '平果酸笋炒牛肉', 'Pingguo Sour Bamboo Shoots Fried Beef', '平果家常菜，本地酸笋配黄牛肉爆炒，酸香开胃，牛肉鲜嫩无膻', 'Homemade dish in Pingguo, local sour bamboo shoots stir-fried with yellow beef, sour and appetizing, tender beef without mutton smell', '平果家常菜馆（马头店）', 'Pingguo Home Cooking Restaurant (Matou Branch)', '酸笋炒牛肉', 'Sour Bamboo Shoots Fried Beef', 38.00, '人均消费', 'Per capita consumption', '10:00-22:00', '10:00-22:00', '广西百色市平果市马头镇铝城大道', 'Lvcheng Avenue, Matou Town, Pingguo City, Baise City, Guangxi', 107.5567000000, 23.3543000000, '13911114444', '店内停车场', 'In-store Parking Lot', 1, '家常菜', 'Home Cooking', 1, '堂食+配送', 'Dine-in + Delivery', 48.0, 10, 1120, 340, 'https://img3.baidu.com/it/u=4455667788,9900112233&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=4455667788,9900112233&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (93, '平果烤香猪', 'Pingguo Roast Fragrant Pig', '平果特色菜，本地小香猪炭火慢烤，皮脆肉嫩，刷秘制酱料，香味浓郁', 'Characteristic dish in Pingguo, local small fragrant pig slowly roasted with charcoal fire, crispy skin and tender meat, brushed with secret sauce, rich fragrance', '平果烤猪店（果化店）', 'Pingguo Roast Pig Shop (Guohua Branch)', '烤香猪', 'Roast Fragrant Pig', 98.00, '人均消费', 'Per capita consumption', '10:00-20:00', '10:00-20:00', '广西百色市平果市果化镇果化街', 'Guohua Street, Guohua Town, Pingguo City, Baise City, Guangxi', 107.4456000000, 23.2654000000, '13911115555', '店内停车场', 'In-store Parking Lot', 1, '特色菜', 'Featured Dish', 1, '堂食+配送', 'Dine-in + Delivery', 49.0, 10, 1150, 340, 'https://img0.baidu.com/it/u=5566778899,0011223344&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=5566778899,0011223344&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (94, '平果玉米粥', 'Pingguo Corn Porridge', '平果经典早餐，本地玉米磨粉熬煮，浓稠香甜，配咸菜、花生，清淡养胃', 'Classic breakfast in Pingguo, local corn ground into powder and boiled, thick and sweet, served with pickles and peanuts, light and stomach-nourishing', '平果早餐店（马头店）', 'Pingguo Breakfast Shop (Matou Branch)', '玉米粥', 'Corn Porridge', 4.00, '人均消费', 'Per capita consumption', '06:00-11:00', '06:00-11:00', '广西百色市平果市马头镇教育路', 'Jiaoyu Road, Matou Town, Pingguo City, Baise City, Guangxi', 107.5890000000, 23.3210000000, '13911116666', '街边停车位', 'Street Parking Spaces', 2, '早餐', 'Breakfast', 0, '堂食', 'Dine-in', 45.0, 10, 880, 260, 'https://img1.baidu.com/it/u=6677889900,1122334455&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=6677889900,1122334455&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (95, '平果烤鱼', 'Pingguo Roast Fish', '平果夜市特色，右江鲜鱼炭火烤制，刷秘制酱料，香辣入味，鱼皮焦香', 'Night market characteristic in Pingguo, fresh fish from Youjiang River roasted with charcoal fire, brushed with secret sauce, spicy and flavorful, crispy fish skin', '平果夜市烤鱼摊（马头店）', 'Pingguo Night Market Roast Fish Stall (Matou Branch)', '烤鱼', 'Roast Fish', 58.00, '人均消费', 'Per capita consumption', '18:00-24:00', '18:00-24:00', '广西百色市平果市马头镇江滨路', 'Jiangbin Road, Matou Town, Pingguo City, Baise City, Guangxi', 107.5789000000, 23.3109000000, '13911117777', '夜市公共停车场', 'Night Market Public Parking Lot', 2, '小吃', 'Snack', 0, '堂食', 'Dine-in', 48.0, 10, 1100, 330, 'https://img2.baidu.com/it/u=7788990011,2233445566&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=7788990011,2233445566&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);
INSERT INTO `food` VALUES (96, '平果手工糍粑', 'Pingguo Handmade Ciba', '平果特色小吃，糯米蒸熟捶打，蘸红糖/黄豆粉，软糯香甜，街头常见', 'Characteristic snack in Pingguo, glutinous rice steamed and beaten, dipped in brown sugar/soybean powder, glutinous and sweet, common on the street', '平果小吃摊（马头店）', 'Pingguo Snack Stall (Matou Branch)', '手工糍粑', 'Handmade Ciba', 4.00, '人均消费', 'Per capita consumption', '08:00-18:00', '08:00-18:00', '广西百色市平果市马头镇朝阳街', 'Chaoyang Street, Matou Town, Pingguo City, Baise City, Guangxi', 107.5890000000, 23.3210000000, '13911118888', '无专用车位（街边可临时停）', 'No dedicated parking (temporary parking on street)', 2, '小吃', 'Snack', 0, '堂食', 'Dine-in', 46.0, 10, 920, 280, 'https://img3.baidu.com/it/u=8899001122,3344556677&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=8899001122,3344556677&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:33:55', '2026-03-21 15:33:55', NULL);

-- ----------------------------
-- Table structure for footprint
-- ----------------------------
DROP TABLE IF EXISTS `footprint`;
CREATE TABLE `footprint`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '足迹ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `target_id` bigint NOT NULL COMMENT '足迹目标ID：景点ID/美食ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型：1-景点，2-美食',
  `browse_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '浏览时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_browse_time`(`browse_time` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '旅行足迹表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of footprint
-- ----------------------------

-- ----------------------------
-- Table structure for interact
-- ----------------------------
DROP TABLE IF EXISTS `interact`;
CREATE TABLE `interact`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '互动ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `target_id` bigint NOT NULL COMMENT '互动目标ID：景点ID/美食ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型：1-景点，2-美食',
  `interact_type` tinyint NOT NULL COMMENT '互动类型：1-景点点赞，2-景点打卡，3-美食点赞，4-美食种草',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_target_interact`(`user_id` ASC, `target_id` ASC, `interact_type` ASC) USING BTREE COMMENT '同一用户对同一目标仅能做一次同类型互动',
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户互动表（点赞/打卡/种草）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of interact
-- ----------------------------

-- ----------------------------
-- Table structure for news
-- ----------------------------
DROP TABLE IF EXISTS `news`;
CREATE TABLE `news`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '资讯ID（主键）',
  `title_cn` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资讯标题（中文）',
  `title_en` varchar(400) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资讯标题（英文）',
  `content_cn` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资讯内容（中文）',
  `content_en` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资讯内容（英文）',
  `cover_img` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '资讯封面图URL',
  `author_id` bigint NOT NULL COMMENT '作者ID（关联user_info.id）（优化：修正关联表）',
  `author_name` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '作者昵称（冗余存储，避免联表查询）',
  `audit_admin_id` bigint NULL DEFAULT NULL COMMENT '审核人ID（关联admin.id）',
  `audit_time` datetime NULL DEFAULT NULL COMMENT '审核时间',
  `read_count` bigint UNSIGNED NULL DEFAULT 0 COMMENT '阅读量（非负）',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：1-已发布 2-草稿 3-下架（便于后台管理）',
  `sort` int NOT NULL DEFAULT 0 COMMENT '排序值（越大越靠前，用于手动置顶）',
  `tags` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT '' COMMENT '资讯标签（英文逗号分隔，如：美食,攻略,亲子）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_create_time`(`create_time` ASC) USING BTREE,
  INDEX `idx_author_id`(`author_id` ASC) USING BTREE,
  INDEX `idx_status_create_time`(`status` ASC, `create_time` ASC) USING BTREE,
  INDEX `idx_delete_status`(`delete_time` ASC, `status` ASC) USING BTREE,
  INDEX `idx_audit_admin_id`(`audit_admin_id` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '文旅资讯/攻略表（中英双语）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of news
-- ----------------------------

-- ----------------------------
-- Table structure for scenic_food_relation
-- ----------------------------
DROP TABLE IF EXISTS `scenic_food_relation`;
CREATE TABLE `scenic_food_relation`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '关联ID',
  `scenic_id` bigint NOT NULL COMMENT '景点ID（关联scenic_spot.id）',
  `food_id` bigint NOT NULL COMMENT '美食ID（关联food.id）',
  `distance` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '距离（如：500米、1公里）',
  `sort` int NULL DEFAULT 0 COMMENT '排序值（越大越靠前）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_scenic_food`(`scenic_id` ASC, `food_id` ASC) USING BTREE,
  INDEX `idx_scenic_id`(`scenic_id` ASC) USING BTREE,
  INDEX `idx_food_id`(`food_id` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '景点-美食关联表（周边美食）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of scenic_food_relation
-- ----------------------------

-- ----------------------------
-- Table structure for scenic_spot
-- ----------------------------
DROP TABLE IF EXISTS `scenic_spot`;
CREATE TABLE `scenic_spot`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '景点ID，主键',
  `name_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点名称（中文）',
  `name_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点名称（英文）',
  `desc_cn` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '景点描述（中文）',
  `desc_en` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '景点描述（英文）',
  `strategy_cn` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '游玩攻略（中文）',
  `strategy_en` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '游玩攻略（英文）',
  `address_cn` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详细地址（中文）',
  `address_en` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '详细地址（英文）（优化：长度从800缩至500）',
  `longitude` decimal(15, 10) NOT NULL COMMENT '经度（高德地图）',
  `latitude` decimal(15, 10) NOT NULL COMMENT '纬度（高德地图）',
  `open_time_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '开放时间（中文）',
  `open_time_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '开放时间（英文）',
  `ticket_info_cn` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '门票信息（中文）',
  `ticket_info_en` varchar(300) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '门票信息（英文）',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联系电话',
  `play_time_cn` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '建议游玩时长（中文）',
  `play_time_en` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '建议游玩时长（英文）',
  `voice_url` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '语音介绍地址',
  `type` tinyint NOT NULL COMMENT '景点类型：1-红色景点，2-自然风光，3-民族村寨',
  `type_cn` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点类型名称（中文）',
  `type_en` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '景点类型名称（英文）',
  `grade_cn` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '景区等级（中文）',
  `grade_en` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '景区等级（英文）',
  `total_score` decimal(3, 1) NULL DEFAULT 0.0 COMMENT '总评分（所有用户评分之和）',
  `score_count` int NULL DEFAULT 0 COMMENT '评分人数',
  `visit_count` bigint NULL DEFAULT 0 COMMENT '访问量（热度）',
  `collect_count` bigint NULL DEFAULT 0 COMMENT '收藏量（热度）',
  `cover_img` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '封面图地址',
  `imgs` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL COMMENT '轮播图地址，多个用逗号分隔',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `idx_type`(`type` ASC) USING BTREE,
  INDEX `idx_total_score`(`total_score` ASC) USING BTREE,
  INDEX `idx_collect_visit`(`collect_count` ASC, `visit_count` ASC) USING BTREE COMMENT '热度排序索引',
  INDEX `idx_type_score`(`type` ASC, `total_score` ASC) USING BTREE COMMENT '按类型+评分筛选',
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE,
  INDEX `idx_name_cn`(`name_cn` ASC) USING BTREE COMMENT '景点名称中文搜索'
) ENGINE = InnoDB AUTO_INCREMENT = 80 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '景点信息表（全字段中英双语）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of scenic_spot
-- ----------------------------
INSERT INTO `scenic_spot` VALUES (1, '百色起义纪念园', 'Baise Uprising Memorial Park', '全国红色旅游经典景区，国家4A级，百色起义核心纪念地，含纪念馆、纪念碑、铜鼓楼，红色文化底蕴深厚', '全国红色旅游经典景区，国家4A级，百色起义核心纪念地，含纪念馆、纪念碑、铜鼓楼，红色文化底蕴深厚', '建议游玩2小时，先逛纪念馆了解历史，登纪念碑俯瞰城区，铜鼓楼体验壮族文化', 'It is recommended to play for 2 hours, visit the memorial hall first to understand history, climb the monument to overlook the urban area, and experience Zhuang culture in the bronze drum tower', '广西百色市右江区城东路112号', '广西百色市右江区城东路112号', 106.6287000000, 23.9055700000, '08:30-17:30(周一闭馆，法定节假日除外)', '08:30-17:30(周一闭馆，法定节假日除外)', '免费', '免费', '0776-2824456', '2小时', '2小时', NULL, 1, '红色景点', 'Red Spot', '4A', '4A', 0.0, 0, 31, 0, '/api/uploads/cbb44825-df30-4bdb-b192-44c5f1946b85.jpg', '/api/uploads/31cb2081-0e66-424c-9019-f0ec6c35905c.jpg,/api/uploads/581cde06-6faf-4317-be97-991fb8a26790.jpg,/api/uploads/97f8f5a9-2429-4bb7-af7b-45d510e2cd2c.jpg', '2026-03-21 15:17:52', '2026-03-25 01:37:34', NULL);
INSERT INTO `scenic_spot` VALUES (2, '澄碧湖风景区', 'Chengbi Lake Scenic Area', '国家3A级，百色“后花园”，湖光山色秀美，有岛屿、溶洞、瀑布，可乘船、垂钓、露营', '国家3A级，百色“后花园”，湖光山色秀美，有岛屿、溶洞、瀑布，可乘船、垂钓、露营', '建议游玩3小时，乘船游湖观两岸风光，登情人岛打卡，周边尝农家菜', 'It is recommended to play for 3 hours, take a boat tour to watch the scenery on both sides of the lake, check in on Lover Island, and taste farm food around', '广西百色市右江区永乐镇澄碧湖路', '广西百色市右江区永乐镇澄碧湖路', 106.5123000000, 23.9789000000, '08:00-18:00', '08:00-18:00', '门票20元/人，船票50元/人', '门票20元/人，船票50元/人', '0776-2851666', '3小时', '3小时', NULL, 2, '自然风光', 'Natural Scenery', '3A', '3A', 0.0, 0, 2, 0, '/api/uploads/3cfcc8f3-4433-4cb9-93fe-9a910d094502.jpg', '/api/uploads/cb944c0f-c7ae-40d6-a9d4-e7f37a2056d8.jpg,/api/uploads/a417f608-59a1-4e39-a290-51ffeddea283.jpg,/api/uploads/e57b12e0-6f71-493f-85e8-60f8e8424e5c.jpg,/api/uploads/73c1db76-4cfc-4a0b-a2f3-f5ce41ecb128.jpg', '2026-03-21 15:17:52', '2026-03-24 23:20:54', NULL);
INSERT INTO `scenic_spot` VALUES (3, '粤东会馆', 'Yuedong Guild Hall', '清代古建筑，百色起义指挥部旧址，国保单位，岭南风格，木雕/石雕工艺精湛', '清代古建筑，百色起义指挥部旧址，国保单位，岭南风格，木雕/石雕工艺精湛', '建议游玩1小时，参观古建筑了解历史，周边逛百色老城区尝小吃', 'It is recommended to play for 1 hour, visit the ancient buildings to understand history, and walk around the old urban area of Baise to taste snacks', '广西百色市右江区解放街39号', '广西百色市右江区解放街39号', 106.6156000000, 23.9012000000, '09:00-17:00(周一闭馆)', '09:00-17:00(周一闭馆)', '免费', '免费', '0776-2822458', '1小时', '1小时', NULL, 1, '红色景点', 'Red Spot', '国保', '国保', 0.0, 0, 9, 0, '/api/uploads/665f1bc1-13a5-424e-89b9-689c89616b8b.jpg', '/api/uploads/4da5b2c0-a6bc-4101-8bc8-33e8ce0d3f6c.jpg,/api/uploads/380a40ae-ab30-406b-9d4c-f43eacb37fe7.jpg,/api/uploads/b5d4188a-c793-4ac6-bce1-6af497e2193e.jpg,/api/uploads/8dcbf7be-1081-4649-ae8b-6e4f9dea2c99.jpg', '2026-03-21 15:17:52', '2026-03-24 19:43:55', NULL);
INSERT INTO `scenic_spot` VALUES (4, '百色园博园', 'Baise Garden Expo Park', '集园林艺术、民俗文化于一体，含12县/区特色展园，展现百色各地风土人情', 'Integrating garden art and folk culture, including 12 characteristic exhibition parks of counties and districts, showing the local customs of Baise', '建议游玩1.5小时，漫步展园打卡各地特色，湖边休闲小憩，春季赏花海', 'It is recommended to play for 1.5 hours, walk through the exhibition park to check in local characteristics, relax by the lake, and enjoy the sea of flowers in spring', '广西百色市右江区龙景街道园博路', 'Yuanbo Road, Longjing Subdistrict, Youjiang District, Baise City, Guangxi', 106.5892000000, 23.8678000000, '06:00-22:00', '06:00-22:00', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=2927922129,3806929118&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=2927922129,3806929118&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=3788252634,1209923321&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (5, '半岛公园', 'Peninsula Park', '右江区核心滨水公园，沿右江而建，绿植茂密，是市民休闲、散步、晨练的好去处', 'The core waterfront park in Youjiang District, built along the Youjiang River, with dense green plants, a good place for citizens to relax, walk and do morning exercises', '建议游玩1小时，沿江散步看江景，傍晚打卡日落，亲子游玩可逛儿童区', 'It is recommended to play for 1 hour, walk along the river to watch the river view, check in the sunset in the evening, and visit the children\'s area for parent-child play', '广西百色市右江区江滨二路', 'Jiangbin 2nd Road, Youjiang District, Baise City, Guangxi', 106.6210000000, 23.9089000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=1890123456,2901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=1890123456,2901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (6, '百色起义烈士纪念碑园', 'Baise Uprising Martyrs Monument Park', '纪念百色起义牺牲烈士的专题园区，纪念碑庄严肃穆，是红色教育、缅怀先烈的重要场所', 'A special park commemorating the martyrs sacrificed in the Baise Uprising, the monument is solemn and an important place for red education and remembering martyrs', '建议游玩1小时，敬献花篮缅怀先烈，参观烈士事迹展，接受红色教育', 'It is recommended to play for 1 hour, present flower baskets to remember martyrs, visit the martyrs\' deeds exhibition and receive red education', '广西百色市右江区迎龙公园内', 'Inside Yinglong Park, Youjiang District, Baise City, Guangxi', 106.6456000000, 23.8987000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-2826789', '1小时', '1 hour', NULL, 1, '红色景点', 'Red Tourism Site', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=2901234567,3901234568&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=2901234567,3901234568&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (7, '大王岭原始森林景区', 'Dawangling Primeval Forest Scenic Area', '国家4A级，桂西最大原始森林，有漂流、瀑布、栈道，被誉为“中国原始森林第一漂”', 'National 4A-level, the largest primeval forest in western Guangxi, with rafting, waterfalls, plank roads, known as the \"first drift in China\'s primeval forest\"', '建议游玩4小时，体验峡谷漂流，徒步森林栈道，夏季避暑首选', 'It is recommended to play for 4 hours, experience canyon rafting, hike the forest plank road, the first choice for summer cooling', '广西百色市右江区大楞乡龙和村', 'Longhe Village, Daleng Township, Youjiang District, Baise City, Guangxi', 106.3210000000, 23.9876000000, '08:00-17:30', '08:00-17:30', '漂流168元/人，门票50元/人', 'Rafting 168 yuan/person, ticket 50 yuan/person', '0776-2858888', '4小时', '4 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=3012345678,4012345679&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=3012345678,4012345679&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=4012345679,5012345680&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (8, '福禄河瀑布群', 'Fulu River Waterfall Group', '右江本土小众自然景点，福禄河沿线多道瀑布，水流清澈，原生态风光，可玩水、徒步、野餐', 'A niche natural scenic spot in Youjiang, there are many waterfalls along the Fulu River, clear water, original ecological scenery, you can play water, hike and have a picnic', '建议游玩2小时，徒步瀑布群沿线，浅滩玩水，自备食材野餐，注意防滑', 'It is recommended to play for 2 hours, hike along the waterfall group, play in the shallow beach, bring your own ingredients for a picnic, and pay attention to anti-slip', '广西百色市右江区四塘镇福禄村', 'Fulu Village, Sitang Town, Youjiang District, Baise City, Guangxi', 106.7890000000, 23.8765000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=4012345679,5012345680&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=4012345679,5012345680&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (9, '右江江滨公园', 'Youjiang Riverside Park', '沿右江打造的滨水休闲公园，有亲水平台、健身步道、观景亭，夜景灯光璀璨，本土市民常去', 'A waterfront leisure park built along the Youjiang River, with water platforms, fitness trails, viewing pavilions, and bright night view lights, often visited by local citizens', '建议游玩1小时，白天散步健身，晚上看江景夜景，打卡网红灯光栈道', 'It is recommended to play for 1 hour, walk and exercise during the day, watch the river view at night, and check in the Internet celebrity light plank road', '广西百色市右江区江滨一路', 'Jiangbin 1st Road, Youjiang District, Baise City, Guangxi', 106.6189000000, 23.9023000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=5012345680,6012345681&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=5012345680,6012345681&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (10, '田州古城', 'Tianzhou Ancient City', '以壮族文化为核心的文旅古城，含壮王府、田州塔、风雨桥，夜景绝美，有本土民俗表演', 'A cultural tourism ancient city with Zhuang culture as the core, including Zhuang Wang Mansion, Tianzhou Tower, Wind and Rain Bridge, stunning night view and local folk performances', '建议游玩2小时，白天逛古城了解壮族文化，晚上看夜景，尝百色本土特色小吃', 'It is recommended to play for 2 hours, walk around the ancient city to understand Zhuang culture during the day, watch the night view at night, and taste local special snacks of Baise', '广西百色市田阳区田州镇敢壮大道', 'Ganzhuang Avenue, Tianzhou Town, Tianyang District, Baise City, Guangxi', 106.9012000000, 23.7890000000, '09:00-23:00', '09:00-23:00', '免费', 'Free', '0776-3288888', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=1890123456,2901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=1890123456,2901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img2.baidu.com/it/u=2901234567,3901234568&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (11, '敢壮山布洛陀文化旅游区', 'Ganzuang Mountain Buluotuo Culture Tourism Area', '国家4A级，壮族始祖布洛陀发源地，壮民族圣山，每年举办本土布洛陀民俗文化节', 'National 4A-level, the birthplace of Buluotuo, the ancestor of the Zhuang people, the holy mountain of the Zhuang people, and the local Buluotuo folk culture festival is held every year', '建议游玩2小时，登敢壮山祭拜布洛陀，参观文化园，节日看本土民俗表演', 'It is recommended to play for 2 hours, climb Ganzuang Mountain to worship Buluotuo, visit the cultural park, and watch local folk performances on festivals', '广西百色市田阳区百育镇敢壮山村', 'Ganzhuangshan Village, Baiyu Town, Tianyang District, Baise City, Guangxi', 106.9876000000, 23.7012000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-3256789', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', '4A', '4A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=3012345678,4012345679&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=3012345678,4012345679&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=4012345679,5012345680&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (12, '田阳湿地公园', 'Tianyang Wetland Park', '集生态保护、休闲观光于一体，湖景优美，植被丰富，田阳本土市民休闲散步好去处', 'Integrating ecological protection and leisure sightseeing, beautiful lake scenery, rich vegetation, a good place for local citizens of Tianyang to walk and relax', '建议游玩1小时，沿湖散步，欣赏湿地景观，亲子游玩打卡本土科普馆', 'It is recommended to play for 1 hour, walk along the lake, enjoy the wetland scenery, and check in the local science museum for parent-child play', '广西百色市田阳区龙河西路', 'Longhe West Road, Tianyang District, Baise City, Guangxi', 106.8901000000, 23.7765000000, '06:00-22:00', '06:00-22:00', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=1234567890,2345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=1234567890,2345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (13, '田阳狮子山景区', 'Tianyang Lion Mountain Scenic Area', '田阳地标性山体，山势雄伟，有本土登山步道、观景台，可俯瞰田阳城区全景', 'The landmark mountain of Tianyang, with majestic mountains, local hiking trails and viewing platforms, you can overlook the whole view of Tianyang urban area', '建议游玩1.5小时，登山徒步锻炼，登观景台看城区全景，傍晚赏日落', 'It is recommended to play for 1.5 hours, hike for exercise, climb the viewing platform to see the whole urban area, and enjoy the sunset in the evening', '广西百色市田阳区田州镇兴城村', 'Xingcheng Village, Tianzhou Town, Tianyang District, Baise City, Guangxi', 106.8876000000, 23.7987000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=2345678901,3456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=2345678901,3456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (14, '那满镇红枫林景区', 'Namang Town Red Maple Forest Scenic Area', '田阳本土小众秋季赏枫胜地，深秋枫林红遍，沿右江分布，山水相依，风光秀美', 'A niche autumn maple viewing resort in Tianyang, the maple forest is red in late autumn, distributed along the Youjiang River, with mountains and rivers dependent on each other and beautiful scenery', '建议游玩2小时，深秋11-12月赏枫，沿江徒步，打卡本土红枫网红点', 'It is recommended to play for 2 hours, enjoy maple leaves in late autumn from November to December, hike along the river, and check in the local red maple Internet celebrity spot', '广西百色市田阳区那满镇露美村', 'Lumei Village, Naman Town, Tianyang District, Baise City, Guangxi', 107.0123000000, 23.7234000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=3456789012,4567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=3456789012,4567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (15, '田阳革命烈士陵园', 'Tianyang Revolutionary Martyrs Cemetery', '纪念田阳革命时期牺牲的烈士，园区庄严肃穆，是田阳本土红色教育重要基地', 'Commemorating the martyrs sacrificed during the Tianyang revolutionary period, the park is solemn and an important local red education base in Tianyang', '建议游玩1小时，敬献鲜花缅怀先烈，参观烈士事迹陈列馆，接受红色教育', 'It is recommended to play for 1 hour, present flowers to remember martyrs, visit the martyrs\' deeds exhibition hall, and receive red education', '广西百色市田阳区田州镇解放东路', 'Jiefang East Road, Tianzhou Town, Tianyang District, Baise City, Guangxi', 106.8987000000, 23.7876000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-3212345', '1小时', '1 hour', NULL, 1, '红色景点', 'Red Tourism Site', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=4567890123,5678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=4567890123,5678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (16, '右江工农民主政府旧址', 'Former Site of Youjiang Workers and Peasants Democratic Government', '国保单位，百色起义重要旧址，记录右江革命根据地发展历程，本土红色资源丰富', 'National key cultural relic protection unit, an important former site of the Baise Uprising, recording the development of the Youjiang Revolutionary Base with rich local red resources', '建议游玩1小时，参观旧址了解革命历史，周边有本土红色展陈，适合红色研学', 'It is recommended to play for 1 hour, visit the former site to understand revolutionary history, there are local red exhibitions around, suitable for red research study', '广西百色市田东县平马镇人民路66号', 'No. 66, Renmin Road, Pingma Town, Tiandong County, Baise City, Guangxi', 107.1234000000, 23.5678000000, '09:00-17:00(周一闭馆)', '09:00-17:00 (Closed on Mondays)', '免费', 'Free', '0776-5223456', '1小时', '1 hour', NULL, 1, '红色景点', 'Red Tourism Site', '国保', 'National Key', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=2345678901,3456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=2345678901,3456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (17, '棋盘滩景区', 'Qipan Beach Scenic Area', '国家3A级，喀斯特地貌，滩面石纹如棋盘，江水清澈，田东本土特色自然景点', 'National 3A-level, karst landform, the beach surface has chessboard-like stone patterns, clear river water, a local characteristic natural scenic spot in Tiandong', '建议游玩2小时，漫步棋盘滩看奇石，浅滩玩水，周边尝田东本土特色农家菜', 'It is recommended to play for 2 hours, walk on Qipan Beach to see exotic stones, play in the shallow beach, and taste local characteristic farm food in Tiandong around', '广西百色市田东县那拔镇六洲村', 'Liuzhou Village, Naba Town, Tiandong County, Baise City, Guangxi', 107.0123000000, 23.7890000000, '08:00-18:00', '08:00-18:00', '门票15元/人', 'Ticket 15 yuan/person', '0776-5312345', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', '3A', '3A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=3456789012,4567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=3456789012,4567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img1.baidu.com/it/u=4567890123,5678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (18, '田东芒果文化园', 'Tiandong Mango Culture Park', '田东芒果节举办地，含本土芒果种植园、博物馆，可采摘、品尝芒果，了解芒果文化', 'The venue of Tiandong Mango Festival, including local mango plantation and museum, you can pick and taste mangoes and understand mango culture', '建议游玩2小时，参观芒果博物馆，芒果成熟季6-8月入园采摘，尝本土芒果制品', 'It is recommended to play for 2 hours, visit the mango museum, enter the garden to pick mangoes from June to August in the mango ripening season, and taste local mango products', '广西百色市田东县祥周镇芒果大道', 'Mangguo Avenue, Xiangzhou Town, Tiandong County, Baise City, Guangxi', 107.0987000000, 23.5123000000, '08:30-18:00', '08:30-18:00', '免费，采摘按斤收费', 'Free, picking charged by jin', '0776-5288888', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=5678901234,6789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=5678901234,6789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (19, '龙须河景区', 'Longxu River Scenic Area', '龙须河田东段风光秀美，江水蜿蜒，两岸峰峦叠嶂，田东本土可竹筏漂流、垂钓', 'The Tiandong section of Longxu River has beautiful scenery, winding river water, overlapping peaks on both sides, local bamboo rafting and fishing in Tiandong', '建议游玩2.5小时，乘竹筏漂流赏两岸风光，江边垂钓，尝本土河鲜美食', 'It is recommended to play for 2.5 hours, take a bamboo raft to enjoy the scenery on both sides, fish by the river, and taste local river fresh food', '广西百色市田东县思林镇龙须河村', 'Longxuhe Village, Silin Town, Tiandong County, Baise City, Guangxi', 107.2345000000, 23.5890000000, '08:00-17:30', '08:00-17:30', '竹筏漂流60元/人', 'Bamboo rafting 60 yuan/person', '0776-5234567', '2.5小时', '2.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=6789012345,7890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=6789012345,7890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (20, '田东湿地公园', 'Tiandong Wetland Park', '集休闲、生态、科普于一体，有湖心岛、亲水平台、荷花池，夏季本土荷花盛开', 'Integrating leisure, ecology and popular science, with lake heart island, water platform, lotus pond, local lotus in full bloom in summer', '建议游玩1小时，沿湖散步，夏季赏荷，亲子游玩逛本土科普长廊', 'It is recommended to play for 1 hour, walk along the lake, enjoy lotus in summer, and visit the local science popularization corridor for parent-child play', '广西百色市田东县平马镇东宁西路', 'Dongning West Road, Pingma Town, Tiandong County, Baise City, Guangxi', 107.1123000000, 23.5789000000, '06:00-22:00', '06:00-22:00', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=7890123456,8901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=7890123456,8901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (21, '印茶镇红色旅游区', 'Yinchazhen Red Tourism Area', '田东本土红色研学基地，含革命旧址、烈士纪念碑，记录当地革命斗争历史', 'Tiandong local red research study base, including revolutionary former sites and martyrs monument, recording the local revolutionary struggle history', '建议游玩1.5小时，参观革命旧址，缅怀先烈，开展本土红色研学活动', 'It is recommended to play for 1.5 hours, visit revolutionary former sites, remember martyrs, and carry out local red research activities', '广西百色市田东县印茶镇印茶村', 'Yincha Village, Yincha Town, Tiandong County, Baise City, Guangxi', 106.9876000000, 23.6789000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-5323456', '1.5小时', '1.5 hours', NULL, 1, '红色景点', 'Red Tourism Site', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=8901234567,9012345678&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=8901234567,9012345678&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (22, '岑王老山国家级自然保护区', 'Cenwang Laoshan National Nature Reserve', '广西第四高峰，国家级保护区，田林本土核心自然景点，原始森林覆盖率高，珍稀动植物多', 'The fourth highest peak in Guangxi, a national nature reserve, the core local natural scenic spot in Tianlin, with high primeval forest coverage and many rare animals and plants', '建议游玩4小时，徒步登山赏原始森林，看瀑布溪流，做好登山准备，山路崎岖', 'It is recommended to play for 4 hours, hike to enjoy the primeval forest, watch waterfalls and streams, prepare for mountaineering, and the mountain road is rugged', '广西百色市田林县浪平镇岑王老山村', 'Cenwanglaoshan Village, Langping Town, Tianlin County, Baise City, Guangxi', 105.7890000000, 24.3210000000, '08:00-17:00', '08:00-17:00', '门票30元/人，向导费50元/人', 'Ticket 30 yuan/person, guide fee 50 yuan/person', '0776-7212345', '4小时', '4 hours', NULL, 2, '自然风光', 'Natural Scenery', '国家级', 'National Level', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=6789012345,7890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=6789012345,7890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img0.baidu.com/it/u=7890123456,8901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (23, '田林风雨桥', 'Tianlin Wind and Rain Bridge', '田林本土壮族特色木质风雨桥，横跨驮娘江，无一颗铁钉，夜景灯光璀璨，建筑工艺精湛', 'Tianlin local Zhuang characteristic wooden wind and rain bridge, spanning the Tuoniang River, without a single iron nail, bright night view and exquisite architectural technology', '建议游玩1小时，漫步风雨桥赏壮族建筑，看驮娘江景，晚上打卡本土夜景', 'It is recommended to play for 1 hour, walk on the Wind and Rain Bridge to enjoy Zhuang architecture, watch the Tuoniang River view, and check in the local night view at night', '广西百色市田林县乐里镇滨河路', 'Binhe Road, Leli Town, Tianlin County, Baise City, Guangxi', 105.6789000000, 24.1234000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=8901234567,9012345678&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=8901234567,9012345678&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (24, '驮娘江景区（田林段）', 'Tuoniang River Scenic Area (Tianlin Section)', '驮娘江田林段原生态风光，江水清澈，两岸峰峦叠嶂，本土可竹筏漂流、露营', 'The original ecological scenery of the Tianlin section of the Tuoniang River, clear water, overlapping peaks on both sides, local bamboo rafting and camping are available', '建议游玩3小时，乘竹筏漂流赏两岸风光，江边露营，品尝本土河鲜美食', 'It is recommended to play for 3 hours, take a bamboo raft to enjoy the scenery on both sides, camp by the river, and taste local river fresh food', '广西百色市田林县八桂瑶族乡驮娘江村', 'Tuoniangjiang Village, Bagui Yao Township, Tianlin County, Baise City, Guangxi', 105.5678000000, 24.2345000000, '08:00-18:00', '08:00-18:00', '竹筏漂流80元/人', 'Bamboo rafting 80 yuan/person', '0776-7234567', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=9012345678,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=9012345678,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (25, '田林仙人洞', 'Tianlin Immortal Cave', '田林本土喀斯特溶洞，洞内钟乳石、石笋千姿百态，灯光映衬下宛如仙境，小众打卡地', 'Tianlin local karst cave, the stalactites and stalagmites in the cave are in various poses, like a fairyland against the light, a niche check-in place', '建议游玩1.5小时，徒步溶洞赏钟乳石景观，跟随本土导游听溶洞传说', 'It is recommended to play for 1.5 hours, hike the cave to enjoy the stalactite scenery, and listen to cave legends with local tour guides', '广西百色市田林县潞城瑶族乡平板村', 'Pingban Village, Lucheng Yao Township, Tianlin County, Baise City, Guangxi', 105.8901000000, 24.2123000000, '08:30-17:30', '08:30-17:30', '门票20元/人', 'Ticket 20 yuan/person', '0776-7223456', '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (26, '利周瑶族乡风情园', 'Lizhou Yao Township Customs Park', '田林本土瑶族文化核心展示区，含瑶族吊脚楼、民俗表演，可体验瑶族服饰、美食', 'The core display area of Tianlin local Yao culture, including Yao stilted buildings and folk performances, you can experience Yao costumes and food', '建议游玩2小时，体验瑶族服饰穿戴，看本土民俗表演，尝瑶族油茶、腊肉', 'It is recommended to play for 2 hours, experience wearing Yao costumes, watch local folk performances, and taste Yao camellia oil and bacon', '广西百色市田林县利周瑶族乡利周村', 'Lizhou Village, Lizhou Yao Township, Tianlin County, Baise City, Guangxi', 105.7654000000, 24.1890000000, '09:00-18:00', '09:00-18:00', '免费，体验项目单独收费', 'Free, experience items charged separately', '0776-7245678', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (27, '田林万亩油茶基地', 'Tianlin Ten Thousand Mu Camellia Oleifera Base', '田林本土特色农业观光基地，油茶林连片，春季花开如雪，可观光、采摘油茶果', 'Tianlin local characteristic agricultural sightseeing base, with continuous camellia oleifera forests, flowers like snow in spring, you can sightseeing and pick camellia oleifera fruits', '建议游玩1.5小时，春季3-4月赏油茶花，了解本土油茶种植工艺，尝茶油制品', 'It is recommended to play for 1.5 hours, enjoy camellia oleifera flowers from March to April in spring, understand the local camellia oleifera planting process, and taste tea oil products', '广西百色市田林县旧州镇平满村', 'Pingman Village, Jiuzhou Town, Tianlin County, Baise City, Guangxi', 105.6543000000, 24.0987000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (28, '浪平镇高山草甸', 'Langping Town Alpine Meadow', '岑王老山脚下田林本土高山草甸，草地辽阔，牛羊成群，原生态草原风光，小众避暑地', 'The local alpine meadow in Tianlin at the foot of Cenwang Laoshan Mountain, with vast grassland, flocks of cattle and sheep, original ecological grassland scenery, a niche summer resort', '建议游玩2小时，徒步草甸赏草原风光，打卡本土网红牛羊群，夏季避暑乘凉', 'It is recommended to play for 2 hours, hike the meadow to enjoy the grassland scenery, check in the local Internet celebrity cattle and sheep group, and cool off in summer', '广西百色市田林县浪平镇浪平村', 'Langping Village, Langping Town, Tianlin County, Baise City, Guangxi', 105.7987000000, 24.3012000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (29, '西林宫保府景区', 'Xilin Gongbao Mansion Scenic Area', '国家4A级，清代名臣岑毓英故居，西林本土岭南壮族特色建筑，保存完整，有文物展陈', 'National 4A-level, the former residence of Cen Yuying, a famous minister of the Qing Dynasty, local Lingnan Zhuang characteristic architecture in Xilin, well preserved with cultural relic exhibitions', '建议游玩1.5小时，参观古建筑，欣赏本土文物展陈，了解岑毓英生平事迹', 'It is recommended to play for 1.5 hours, visit ancient buildings, appreciate local cultural relic exhibitions, and understand the life story of Cen Yuying', '广西百色市西林县那劳镇那劳村', 'Nalao Village, Nalao Town, Xilin County, Baise City, Guangxi', 105.0123000000, 24.5678000000, '09:00-17:00', '09:00-17:00', '门票20元/人', 'Ticket 20 yuan/person', '0776-8612345', '1.5小时', '1.5 hours', NULL, 3, '民族村寨', 'Ethnic Village', '4A', '4A', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img0.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (30, '西林万峰湖景区', 'Xilin Wanfeng Lake Scenic Area', '万峰湖西林段，湖域广阔，湖光山色，多岛屿，西林本土“野钓天堂”，民族风情浓郁', 'The Xilin section of Wanfeng Lake, with vast lake area, beautiful lakes and mountains, many islands, the local \"wild fishing paradise\" in Xilin, with strong ethnic customs', '建议游玩3小时，乘船游湖观岛屿，体验本土野钓，品尝万峰湖鱼鲜', 'It is recommended to play for 3 hours, take a boat tour to watch the islands, experience local wild fishing, and taste the fresh fish of Wanfeng Lake', '广西百色市西林县马蚌镇万峰湖村', 'Wanfenghu Village, Mabang Town, Xilin County, Baise City, Guangxi', 104.8901000000, 24.4567000000, '08:00-18:00', '08:00-18:00', '船票60元/人，钓鱼按天收费', 'Boat ticket 60 yuan/person, fishing charged by day', '0776-8634567', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (31, '西林驮娘江大峡谷', 'Xilin Tuoniang River Grand Canyon', '驮娘江西林段大峡谷，悬崖峭壁，江水湍急，有瀑布溶洞，西林本土可漂流、探险', 'The grand canyon of the Xilin section of the Tuoniang River, steep cliffs, rapid river water, waterfalls and karst caves, local rafting and exploration in Xilin', '建议游玩2.5小时，体验峡谷漂流，观赏悬崖瀑布，探秘本土溶洞景观', 'It is recommended to play for 2.5 hours, experience canyon rafting, watch cliff waterfalls, and explore local karst cave landscapes', '广西百色市西林县普合苗族乡驮娘江村', 'Tuoniangjiang Village, Puhe Miao Township, Xilin County, Baise City, Guangxi', 105.1234000000, 24.6789000000, '08:30-17:30', '08:30-17:30', '漂流120元/人', 'Rafting 120 yuan/person', '0776-8623456', '2.5小时', '2.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (32, '普合苗族乡风情园', 'Puhe Miao Township Customs Park', '西林本土苗族文化展示区，含苗族吊脚楼、芦笙堂，可体验苗族服饰、歌舞、美食', 'Xilin local Miao culture display area, including Miao stilted buildings and Lusheng Hall, you can experience Miao costumes, singing and dancing, and food', '建议游玩2小时，体验苗族服饰，看本土芦笙歌舞，尝苗族酸汤、糯米饭', 'It is recommended to play for 2 hours, experience wearing Miao costumes, watch local Lusheng singing and dancing, and taste Miao sour soup and glutinous rice', '广西百色市西林县普合苗族乡普合村', 'Puhe Village, Puhe Miao Township, Xilin County, Baise City, Guangxi', 105.1098000000, 24.6543000000, '09:00-18:00', '09:00-18:00', '免费，体验项目单独收费', 'Free, experience items charged separately', '0776-8645678', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (33, '西林古障古镇', 'Xilin Guzhang Ancient Town', '西林本土百年古镇，壮族/苗族风情浓郁，古建筑保存完好，有本土特色市集', 'Xilin local century-old ancient town, strong Zhuang/Miao customs, well-preserved ancient buildings, with local characteristic markets', '建议游玩1.5小时，逛古镇看古建筑，赶本土市集，尝壮苗特色小吃', 'It is recommended to play for 1.5 hours, walk around the ancient town to see ancient buildings, go to local markets, and taste Zhuang and Miao characteristic snacks', '广西百色市西林县古障镇古障村', 'Guzhang Village, Guzhang Town, Xilin County, Baise City, Guangxi', 104.9876000000, 24.3456000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (34, '西林九龙山景区', 'Xilin Jiulong Mountain Scenic Area', '西林本土喀斯特山体，九峰相连如九龙，有登山步道、观景台，可俯瞰滇桂交界风光', 'Xilin local karst mountain, nine peaks connected like nine dragons, with hiking trails and viewing platforms, you can overlook the scenery at the junction of Yunnan and Guangxi', '建议游玩2小时，登山徒步赏峰林景观，登观景台看滇桂交界风光', 'It is recommended to play for 2 hours, hike to enjoy the peak forest scenery, climb the viewing platform to see the scenery at the junction of Yunnan and Guangxi', '广西百色市西林县八达镇九龙村', 'Jiulong Village, Bada Town, Xilin County, Baise City, Guangxi', 105.0987000000, 24.5432000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (35, '隆林天生桥景区', 'Longlin Tianshengqiao Scenic Area', '国家3A级，滇桂交界天生桥水电站库区，湖光山色，有“高原天湖”之称，本土垂钓/游船胜地', 'National 3A-level, Tianshengqiao Hydropower Station reservoir area at the junction of Yunnan and Guangxi, beautiful lakes and mountains, known as \"Plateau Tianhu\", a local fishing/boating resort', '建议游玩3小时，乘船游库区赏湖景，体验本土野钓，尝库区鱼鲜', 'It is recommended to play for 3 hours, take a boat tour to enjoy the lake view, experience local wild fishing, and taste reservoir fish', '广西百色市隆林各族自治县天生桥镇马窝村', 'Mawo Village, Tianshengqiao Town, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.0123000000, 24.8765000000, '08:00-18:00', '08:00-18:00', '船票50元/人，钓鱼按天收费', 'Boat ticket 50 yuan/person, fishing charged by day', '0776-8212345', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', '3A', '3A', 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (36, '隆林金钟山黑叶猴自然保护区', 'Longlin Jinzhongshan Francois Leaf Monkey Nature Reserve', '国家级保护区，隆林本土核心生态景点，全球最大黑叶猴种群栖息地，原生态森林', 'National nature reserve, the core local ecological scenic spot in Longlin, the world\'s largest habitat of Francois leaf monkey population, original ecological forest', '建议游玩3小时，徒步森林观黑叶猴，了解本土生态保护，跟随专业向导', 'It is recommended to play for 3 hours, hike the forest to watch Francois leaf monkeys, understand local ecological protection, and follow professional guides', '广西百色市隆林各族自治县金钟山乡金钟山社区', 'Jinzhongshan Community, Jinzhongshan Township, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.2345000000, 24.7654000000, '08:00-17:00', '08:00-17:00', '门票40元/人，向导费60元/人', 'Ticket 40 yuan/person, guide fee 60 yuan/person', '0776-8234567', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', '国家级', 'National Level', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (37, '隆林德峨苗族风情乡', 'Longlin De\'e Miao Customs Township', '隆林本土苗族文化核心区，“中国苗族服饰文化之乡”，有民俗表演、服饰展示', 'Longlin local core area of Miao culture, \"Hometown of Chinese Miao Costume Culture\", with folk performances and costume exhibitions', '建议游玩2小时，体验苗族服饰，看本土跳坡节表演，尝苗族特色美食', 'It is recommended to play for 2 hours, experience Miao costumes, watch local Tiaopo Festival performances, and taste Miao characteristic food', '广西百色市隆林各族自治县德峨镇德峨村', 'De\'e Village, De\'e Town, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.3456000000, 24.7890000000, '09:00-18:00', '09:00-18:00', '免费，体验项目单独收费', 'Free, experience items charged separately', '0776-8223456', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (38, '隆林冷水瀑布', 'Longlin Lengshui Waterfall', '隆林本土“南国第一瀑”，瀑布落差大，夏季水量充沛，周边原生态森林茂密', 'Longlin local \"No.1 Waterfall in South China\", large drop of waterfall, abundant water in summer, dense original ecological forest around', '建议游玩2小时，徒步观瀑布景观，夏季避暑，周边尝本土农家菜', 'It is recommended to play for 2 hours, hike to watch the waterfall scenery, cool off in summer, and taste local farm food around', '广西百色市隆林各族自治县新州镇冷水村', 'Lengshui Village, Xinzhou Town, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.1234000000, 24.8901000000, '08:00-18:00', '08:00-18:00', '门票15元/人', 'Ticket 15 yuan/person', '0776-8245678', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (39, '隆林者浪乡田园风光区', 'Longlin Zhelang Township Pastoral Scenic Area', '隆林本土喀斯特田园，稻田连片，峰林相依，春季油菜花、秋季稻田风光绝美', 'Longlin local karst pastoral, continuous rice fields, peaks dependent on each other, beautiful rape flowers in spring and rice fields in autumn', '建议游玩1.5小时，徒步田园赏自然风光，春季打卡油菜花，秋季看金色稻田', 'It is recommended to play for 1.5 hours, hike the pastoral to enjoy natural scenery, check in rape flowers in spring, and watch golden rice fields in autumn', '广西百色市隆林各族自治县者浪乡者浪村', 'Zhelang Village, Zhelang Township, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.2123000000, 24.8765000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (40, '隆林民族文化广场', 'Longlin Ethnic Culture Square', '隆林本土展示多民族文化的核心广场，有民族雕塑、文化长廊，夜间有本土民俗活动', 'Longlin local core square displaying multi-ethnic culture, with ethnic sculptures and cultural corridors, and local folk activities at night', '建议游玩1小时，逛文化广场了解多民族文化，晚上看本土民俗表演', 'It is recommended to play for 1 hour, walk around the cultural square to understand multi-ethnic culture, and watch local folk performances at night', '广西百色市隆林各族自治县新州镇民生街', 'Minsheng Street, Xinzhou Town, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.1987000000, 24.8876000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (41, '隆林平流壮寨', 'Longlin Pingliu Zhuang Village', '隆林本土壮族古寨，吊脚楼保存完好，壮族风情浓郁，可体验本土壮家生活', 'Longlin local ancient Zhuang village, well-preserved stilted buildings, strong Zhuang customs, you can experience local Zhuang family life', '建议游玩2小时，逛壮寨看古建筑，体验壮家织布、酿酒，尝壮家五色糯米饭', 'It is recommended to play for 2 hours, walk around the Zhuang village to see ancient buildings, experience Zhuang family weaving and winemaking, and taste Zhuang family five-color glutinous rice', '广西百色市隆林各族自治县沙梨乡平流村', 'Pingliu Village, Shali Township, Longlin Various Nationalities Autonomous County, Baise City, Guangxi', 105.4321000000, 24.7654000000, '09:00-18:00', '09:00-18:00', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (42, '靖西通灵大峡谷', 'Jingxi Tongling Grand Canyon', '国家4A级，喀斯特峡谷，瀑布、溶洞、地下河并存，靖西核心自然景点', 'National 4A-level, karst canyon, coexisting waterfalls, karst caves and underground rivers, the core natural scenic spot in Jingxi', '建议游玩3小时，徒步峡谷看瀑布，探秘溶洞，夏季避暑首选', 'It is recommended to play for 3 hours, hike the canyon to see waterfalls, explore karst caves, the first choice for summer cooling', '广西百色市靖西市湖润镇新灵村', 'Xinling Village, Hurun Town, Jingxi City, Baise City, Guangxi', 106.4567000000, 23.1234000000, '08:00-17:30', '08:00-17:30', '门票115元/人', 'Ticket 115 yuan/person', '0776-6180000', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (43, '靖西鹅泉景区', 'Jingxi Equan Scenic Area', '国家4A级，“靖西八景”之首，喀斯特涌泉，田园风光秀美，可乘船、打卡古桥', 'National 4A-level, the first of \"Jingxi Eight Scenes\", karst spring, beautiful pastoral scenery, you can boat and check in ancient bridges', '建议游玩2小时，乘船游泉池，打卡百年古桥，周边尝靖西本土美食', 'It is recommended to play for 2 hours, take a boat tour of the spring pool, check in the century-old ancient bridge, and taste local food in Jingxi around', '广西百色市靖西市新靖镇鹅泉村', 'Equan Village, Xinjing Town, Jingxi City, Baise City, Guangxi', 106.3456000000, 23.2345000000, '08:00-17:30', '08:00-17:30', '门票48元/人，船票20元/人', 'Ticket 48 yuan/person, boat ticket 20 yuan/person', '0776-6218888', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (44, '靖西古龙山大峡谷', 'Jingxi Gulongshan Grand Canyon', '国家4A级，峡谷、瀑布、暗河一体，可漂流、徒步，靖西本土“峡谷秘境”', 'National 4A-level, integrated canyon, waterfall and underground river, you can raft and hike, the local \"canyon secret land\" in Jingxi', '建议游玩3小时，体验暗河漂流，徒步峡谷看瀑布，探秘原生态景观', 'It is recommended to play for 3 hours, experience underground river rafting, hike the canyon to see waterfalls, and explore original ecological landscapes', '广西百色市靖西市湖润镇古龙村', 'Gulong Village, Hurun Town, Jingxi City, Baise City, Guangxi', 106.4890000000, 23.1098000000, '08:00-17:00', '08:00-17:00', '漂流198元/人，门票80元/人', 'Rafting 198 yuan/person, ticket 80 yuan/person', '0776-6190000', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (45, '靖西旧州古镇', 'Jingxi Jiuzhou Ancient Town', '国家4A级，“中国绣球之乡”，壮族古镇，绣球制作、古建筑、田园风光融为一体', 'National 4A-level, \"Hometown of Chinese Embroidery Balls\", Zhuang ancient town, integrating embroidery ball making, ancient buildings and pastoral scenery', '建议游玩2小时，体验绣球制作，逛古镇看古建筑，打卡田园风光', 'It is recommended to play for 2 hours, experience embroidery ball making, walk around the ancient town to see ancient buildings, and check in pastoral scenery', '广西百色市靖西市新靖镇旧州村', 'Jiuzhou Village, Xinjing Town, Jingxi City, Baise City, Guangxi', 106.2345000000, 23.3456000000, '08:30-17:30', '08:30-17:30', '门票60元/人', 'Ticket 60 yuan/person', '0776-6223456', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', '4A', '4A', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (46, '靖西渠洋湖', 'Jingxi Quyang Lake', '靖西本土喀斯特湖泊，湖域广阔，多岛屿，可乘船赏峰林湖景，小众打卡地', 'Jingxi local karst lake, vast lake area, many islands, you can take a boat to enjoy the peak forest lake view, a niche check-in place', '建议游玩2.5小时，乘船游湖赏峰林，登岛屿打卡，周边尝本土农家菜', 'It is recommended to play for 2.5 hours, take a boat tour to enjoy the peak forest, check in on islands, and taste local farm food around', '广西百色市靖西市渠洋镇渠洋村', 'Quyang Village, Quyang Town, Jingxi City, Baise City, Guangxi', 106.1234000000, 23.4567000000, '08:00-18:00', '08:00-18:00', '船票50元/人，免费入园', 'Boat ticket 50 yuan/person, free entry', NULL, '2.5小时', '2.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (47, '靖西爱布瀑布群', 'Jingxi Aibu Waterfall Group', '靖西本土小众瀑布群，多道瀑布相连，原生态风光，夏季水量充沛，可玩水、徒步', 'Jingxi local niche waterfall group, multiple waterfalls connected, original ecological scenery, abundant water in summer, you can play water and hike', '建议游玩2小时，徒步瀑布群沿线，浅滩玩水，夏季避暑，自备野餐', 'It is recommended to play for 2 hours, hike along the waterfall group, play in the shallow beach, cool off in summer, and bring your own picnic', '广西百色市靖西市化峒镇爱布村', 'Aibu Village, Huadong Town, Jingxi City, Baise City, Guangxi', 106.3987000000, 23.2123000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (48, '靖西三叠岭瀑布', 'Jingxi Sandieling Waterfall', '靖西本土地标性瀑布，桂西高速旁，三叠落差，雨季气势磅礴，免费打卡地', 'Jingxi local landmark waterfall, beside Guangxi West Expressway, three stacks of drop, magnificent in rainy season, free check-in place', '建议游玩1小时，观瀑布景观，打卡高速旁网红瀑布，拍照留念', 'It is recommended to play for 1 hour, watch the waterfall scenery, check in the Internet celebrity waterfall beside the expressway, and take photos as a souvenir', '广西百色市靖西市湖润镇三叠岭村', 'Sandieling Village, Hurun Town, Jingxi City, Baise City, Guangxi', 106.4987000000, 23.1987000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (49, '靖西巴泽梯田', 'Jingxi Baze Terraced Fields', '靖西本土壮族梯田，四季风光不同，春季灌水、秋季金黄，小众田园打卡地', 'Jingxi local Zhuang terraced fields, different scenery in four seasons, irrigation in spring, golden in autumn, a niche pastoral check-in place', '建议游玩1.5小时，徒步梯田赏自然风光，春季打卡镜面梯田，秋季看金色稻浪', 'It is recommended to play for 1.5 hours, hike the terraced fields to enjoy natural scenery, check in mirror terraced fields in spring, and watch golden rice waves in autumn', '广西百色市靖西市壬庄乡巴泽村', 'Baze Village, Renzhuang Township, Jingxi City, Baise City, Guangxi', 106.0987000000, 23.1890000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (50, '那坡黑衣壮风情园', 'Napo Heiyi Zhuang Customs Park', '国家3A级，中国黑衣壮聚居地，展示黑衣壮服饰、歌舞、建筑，那坡核心民族景点', 'National 3A-level, the settlement of Chinese Heiyi Zhuang, displaying Heiyi Zhuang costumes, singing and dancing, architecture, the core ethnic scenic spot in Napo', '建议游玩2小时，体验黑衣壮服饰，看本土民俗表演，尝黑衣壮特色美食', 'It is recommended to play for 2 hours, experience Heiyi Zhuang costumes, watch local folk performances, and taste Heiyi Zhuang characteristic food', '广西百色市那坡县城厢镇龙华村', 'Longhua Village, Chengxiang Town, Napo County, Baise City, Guangxi', 105.8901000000, 23.4567000000, '09:00-17:30', '09:00-17:30', '门票50元/人', 'Ticket 50 yuan/person', '0776-6802345', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', '3A', '3A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img1.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (51, '那坡老虎跳峡谷', 'Napo Laohutiao Grand Canyon', '那坡本土中越交界峡谷，江水湍急，悬崖峭壁，原生态边关风光，小众探险地', 'Napo local canyon at the Sino-Vietnamese border, rapid river water, steep cliffs, original ecological border scenery, a niche adventure place', '建议游玩2小时，徒步峡谷看边关风光，打卡中越界碑，注意边境规定', 'It is recommended to play for 2 hours, hike the canyon to see border scenery, check in Sino-Vietnamese boundary monument, and pay attention to border regulations', '广西百色市那坡县百南乡规良村', 'Guiliang Village, Bainan Township, Napo County, Baise City, Guangxi', 105.7890000000, 23.2345000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (52, '那坡白云山原始森林', 'Napo Baiyun Mountain Primeval Forest', '那坡本土原始森林，植被茂密，珍稀动植物多，可徒步、露营，小众避暑地', 'Napo local primeval forest, dense vegetation, many rare animals and plants, you can hike and camp, a niche summer resort', '建议游玩3小时，徒步森林赏原生态风光，露营体验，做好防虫准备', 'It is recommended to play for 3 hours, hike the forest to enjoy original ecological scenery, experience camping, and prepare for insect prevention', '广西百色市那坡县德隆乡德孚村', 'Defu Village, Delong Township, Napo County, Baise City, Guangxi', 105.9876000000, 23.3456000000, '08:00-17:00', '08:00-17:00', '免费', 'Free', NULL, '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (53, '那坡百省乡边境风光区', 'Napo Baisheng Township Border Scenic Area', '那坡本土中越边境乡，有界碑、边境村寨，壮族/瑶族风情浓郁，边关特色鲜明', 'Napo local Sino-Vietnamese border township, with boundary monuments and border villages, strong Zhuang/Yao customs, distinct border characteristics', '建议游玩2小时，逛边境村寨，打卡界碑，体验边境民族风情', 'It is recommended to play for 2 hours, walk around border villages, check in boundary monuments, and experience border ethnic customs', '广西百色市那坡县百省乡百省村', 'Baisheng Village, Baisheng Township, Napo County, Baise City, Guangxi', 105.7654000000, 23.1234000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (54, '那坡烈士陵园', 'Napo Martyrs Cemetery', '纪念那坡边境自卫反击战烈士，园区庄严肃穆，那坡本土红色教育重要基地', 'Commemorating the martyrs of the Napo border self-defense counterattack war, the park is solemn and an important local red education base in Napo', '建议游玩1小时，敬献鲜花缅怀先烈，参观烈士事迹展，接受红色教育', 'It is recommended to play for 1 hour, present flowers to remember martyrs, visit the martyrs deeds exhibition, and receive red education', '广西百色市那坡县城厢镇陵园路', 'Lingyuan Road, Chengxiang Town, Napo County, Baise City, Guangxi', 105.8765000000, 23.4678000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-6823456', '1小时', '1 hour', NULL, 1, '红色景点', 'Red Tourism Site', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (55, '那坡吞力黑衣壮寨', 'Napo Tunli Heiyi Zhuang Village', '那坡本土纯黑衣壮村寨，吊脚楼保存完好，可体验黑衣壮原生态生活方式', 'Napo local pure Heiyi Zhuang village, well-preserved stilted buildings, you can experience the original ecological lifestyle of Heiyi Zhuang', '建议游玩1.5小时，逛黑衣壮寨，体验织布、染布，尝本土黑衣壮农家菜', 'It is recommended to play for 1.5 hours, walk around the Heiyi Zhuang village, experience weaving and dyeing, and taste local Heiyi Zhuang farm food', '广西百色市那坡县龙合镇吞力村', 'Tunli Village, Longhe Town, Napo County, Baise City, Guangxi', 105.9234000000, 23.5678000000, '09:00-17:00', '09:00-17:00', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (56, '德保吉星岩', 'Debao Jixingyan Cave', '国家4A级，喀斯特溶洞，钟乳石千姿百态，灯光映衬如仙境，德保核心自然景点', 'National 4A-level, karst cave, stalactites in various poses, like a fairyland against the light, the core natural scenic spot in Debao', '建议游玩1.5小时，徒步溶洞赏钟乳石，跟随导游听溶洞传说，拍照打卡', 'It is recommended to play for 1.5 hours, hike the cave to enjoy stalactites, listen to cave legends with guides, and take photos', '广西百色市德保县燕峒乡那布村', 'Nabu Village, Yandong Township, Debao County, Baise City, Guangxi', 106.5678000000, 23.3456000000, '08:00-17:30', '08:00-17:30', '门票80元/人', 'Ticket 80 yuan/person', '0776-3823456', '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img0.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (57, '德保红叶森林公园', 'Debao Red Leaf Forest Park', '国家4A级，秋季枫叶红遍，德保本土“红叶胜地”，峰林与红叶相映成趣', 'National 4A-level, maple leaves red in autumn, Debao local \"red leaf resort\", peak forest and red leaves set off each other', '建议游玩2小时，秋季11-12月赏红叶，徒步森林，打卡网红红叶点', 'It is recommended to play for 2 hours, enjoy red leaves from November to December in autumn, hike the forest, and check in Internet celebrity red leaf spots', '广西百色市德保县城关镇红叶村', 'Hongye Village, Chengguan Town, Debao County, Baise City, Guangxi', 106.4567000000, 23.4567000000, '08:00-18:00', '08:00-18:00', '门票60元/人', 'Ticket 60 yuan/person', '0776-3834567', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (58, '德保曼贝侬小西湖', 'Debao Manbeinong West Lake', '德保本土喀斯特湖泊，湖景秀美，田园相依，有亲水步道、观景亭，小众休闲地', 'Debao local karst lake, beautiful lake scenery, pastoral dependent, with hydrophilic trails and viewing pavilions, a niche leisure place', '建议游玩1.5小时，沿湖散步，赏湖光山色，亲子游玩打卡本土休闲区', 'It is recommended to play for 1.5 hours, walk along the lake, enjoy the lakes and mountains, and check in local leisure areas for parent-child play', '广西百色市德保县城关镇曼贝侬村', 'Manbeinong Village, Chengguan Town, Debao County, Baise City, Guangxi', 106.4890000000, 23.4789000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (59, '德保矮马王国', 'Debao Pony Kingdom', '德保本土矮马文化主题景区，可与矮马互动、骑行，了解德保矮马历史文化', 'Debao local pony culture theme scenic area, you can interact and ride with ponies, understand the history and culture of Debao ponies', '建议游玩2小时，与矮马互动，体验骑行，参观矮马文化博物馆', 'It is recommended to play for 2 hours, interact with ponies, experience riding, and visit the pony culture museum', '广西百色市德保县足荣镇足荣村', 'Zurong Village, Zurong Town, Debao County, Baise City, Guangxi', 106.6789000000, 23.3210000000, '09:00-17:30', '09:00-17:30', '门票88元/人，骑行30元/次', 'Ticket 88 yuan/person, riding 30 yuan/time', '0776-3856789', '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (60, '德保独秀峰景区', 'Debao Duxiu Peak Scenic Area', '德保本土地标性山体，孤峰独秀，有登山步道、观景台，可俯瞰德保城区全景', 'Debao local landmark mountain, solitary peak, with hiking trails and viewing platforms, you can overlook the whole view of Debao urban area', '建议游玩1小时，登山徒步锻炼，登观景台看城区全景，傍晚赏日落', 'It is recommended to play for 1 hour, hike for exercise, climb the viewing platform to see the whole urban area, and enjoy the sunset in the evening', '广西百色市德保县城关镇独秀村', 'Duxiu Village, Chengguan Town, Debao County, Baise City, Guangxi', 106.4789000000, 23.4678000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (61, '德保足荣古镇', 'Debao Zurong Ancient Town', '德保本土文旅古镇，融合壮族文化与现代休闲，有美食街、民俗表演，夜间热闹', 'Debao local cultural tourism ancient town, integrating Zhuang culture and modern leisure, with food streets and folk performances, lively at night', '建议游玩2小时，逛古镇尝本土美食，看民俗表演，打卡网红夜景', 'It is recommended to play for 2 hours, walk around the ancient town to taste local food, watch folk performances, and check in Internet celebrity night view', '广西百色市德保县足荣镇足荣街', 'Zurong Street, Zurong Town, Debao County, Baise City, Guangxi', 106.6890000000, 23.3123000000, '09:00-22:00', '09:00-22:00', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (62, '乐业大石围天坑群', 'Leye Dashanwei Tiankeng Group', '国家4A级，世界最大天坑群，喀斯特奇观，乐业核心自然景点，震撼壮观', 'National 4A-level, the worlds largest tiankeng group, karst wonders, the core natural scenic spot in Leye, shocking and spectacular', '建议游玩4小时，徒步天坑观景台，了解喀斯特地貌，跟随专业向导', 'It is recommended to play for 4 hours, hike the tiankeng viewing platform, understand karst landform, and follow professional guides', '广西百色市乐业县同乐镇刷把村', 'Shuaba Village, Tongle Town, Leye County, Baise City, Guangxi', 106.4321000000, 24.7654000000, '08:00-17:00', '08:00-17:00', '门票98元/人', 'Ticket 98 yuan/person', '0776-7922345', '4小时', '4 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img3.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (63, '乐业布柳河仙人桥景区', 'Leye Buliu River Immortal Bridge Scenic Area', '国家3A级，布柳河上天然石拱桥，“世界第一天然桥”，可竹筏漂流赏景', 'National 3A-level, natural stone arch bridge on Buliu River, \"the worlds first natural bridge\", you can take a bamboo raft to enjoy the scenery', '建议游玩3小时，乘竹筏漂流看仙人桥，赏两岸喀斯特峰林，尝本土河鲜', 'It is recommended to play for 3 hours, take a bamboo raft to see the Immortal Bridge, enjoy the karst peak forest on both sides, and taste local river fresh food', '广西百色市乐业县新化镇磨里村', 'Moli Village, Xinhua Town, Leye County, Baise City, Guangxi', 106.5432000000, 24.6543000000, '08:00-17:30', '08:00-17:30', '竹筏漂流80元/人，门票40元/人', 'Bamboo rafting 80 yuan/person, ticket 40 yuan/person', '0776-7934567', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', '3A', '3A', 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (64, '乐业凤山地质公园博物馆', 'Leye Fengshan Geopark Museum', '乐业本土地质科普基地，展示天坑群、溶洞等喀斯特地貌形成原因，亲子研学首选', 'Leye local geological science popularization base, displaying the formation reasons of karst landforms such as tiankeng groups and karst caves, the first choice for parent-child research', '建议游玩1小时，参观博物馆，了解地质知识，观看科普影片', 'It is recommended to play for 1 hour, visit the museum, understand geological knowledge, and watch popular science films', '广西百色市乐业县同乐镇迎宾大道', 'Yingbin Avenue, Tongle Town, Leye County, Baise City, Guangxi', 106.4123000000, 24.7567000000, '09:00-17:00 (周一闭馆)', '09:00-17:00 (Closed on Mondays)', '免费', 'Free', '0776-7945678', '1小时', '1 hour', NULL, 4, '其他', 'Other', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (65, '乐业火卖生态村', 'Leye Huomai Ecological Village', '乐业本土原生态村寨，天坑群旁，可徒步、观星、体验农家生活，小众避暑地', 'Leye local original ecological village, beside the tiankeng group, you can hike, stargaze, experience farm life, a niche summer resort', '建议游玩2小时，徒步村寨看天坑远景，夜间观星，尝本土农家菜', 'It is recommended to play for 2 hours, hike the village to see the distant view of tiankeng, stargaze at night, and taste local farm food', '广西百色市乐业县同乐镇火卖村', 'Huomai Village, Tongle Town, Leye County, Baise City, Guangxi', 106.4012000000, 24.7890000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (66, '乐业五台山景区', 'Leye Wutai Mountain Scenic Area', '乐业本土高山景区，五峰相连，森林茂密，可徒步、露营，夏季避暑胜地', 'Leye local alpine scenic area, five peaks connected, dense forest, you can hike and camp, a summer resort', '建议游玩3小时，徒步登山赏森林风光，露营体验，做好登山准备', 'It is recommended to play for 3 hours, hike to enjoy the forest scenery, experience camping, and prepare for mountaineering', '广西百色市乐业县逻沙乡五台山社区', 'Wutaishan Community, Luosha Township, Leye County, Baise City, Guangxi', 106.3210000000, 24.8765000000, '08:00-17:00', '08:00-17:00', '免费', 'Free', NULL, '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=789012345,890123456&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (67, '乐业革命烈士陵园', 'Leye Revolutionary Martyrs Cemetery', '纪念乐业革命时期牺牲的烈士，园区庄严肃穆，乐业本土红色教育重要基地', 'Commemorating the martyrs sacrificed during the Leye revolutionary period, the park is solemn and an important local red education base in Leye', '建议游玩1小时，敬献鲜花缅怀先烈，参观烈士事迹展，接受红色教育', 'It is recommended to play for 1 hour, present flowers to remember martyrs, visit the martyrs deeds exhibition, and receive red education', '广西百色市乐业县同乐镇陵园路', 'Lingyuan Road, Tongle Town, Leye County, Baise City, Guangxi', 106.4234000000, 24.7789000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', '0776-7956789', '1小时', '1 hour', NULL, 1, '红色景点', 'Red Tourism Site', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=890123456,901234567&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (68, '凌云茶山金字塔', 'Lingyun Tea Mountain Pyramid', '国家4A级，凌云本土茶叶种植基地，茶山层叠如金字塔，茶文化浓郁，可采茶、品茶', 'National 4A-level, Lingyun local tea planting base, tea mountains stacked like pyramids, strong tea culture, you can pick and taste tea', '建议游玩2小时，徒步茶山赏风光，体验采茶，品尝凌云白毫茶', 'It is recommended to play for 2 hours, hike the tea mountain to enjoy the scenery, experience tea picking, and taste Lingyun Baihao tea', '广西百色市凌云县加尤镇案相村', 'Anxiang Village, Jiayou Town, Lingyun County, Baise City, Guangxi', 106.6789000000, 24.5678000000, '08:00-18:00', '08:00-18:00', '门票60元/人', 'Ticket 60 yuan/person', '0776-7612345', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=901234567,123456789&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500,https://img1.baidu.com/it/u=123456789,234567890&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (69, '凌云纳灵洞', 'Lingyun Naling Cave', '凌云本土喀斯特溶洞，钟乳石形态奇特，有“亚洲神奇第一洞”之称，小众打卡地', 'Lingyun local karst cave, stalactites with strange shapes, known as \"Asias magical first cave\", a niche check-in place', '建议游玩1.5小时，徒步溶洞赏钟乳石，听溶洞传说，拍照打卡', 'It is recommended to play for 1.5 hours, hike the cave to enjoy stalactites, listen to cave legends, and take photos', '广西百色市凌云县泗城镇纳灵村', 'Naling Village, Sicheng Town, Lingyun County, Baise City, Guangxi', 106.5678000000, 24.5789000000, '08:30-17:00', '08:30-17:00', '门票80元/人', 'Ticket 80 yuan/person', '0776-7623456', '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=234567890,345678901&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (70, '凌云水源洞', 'Lingyun Shuiyuan Cave', '凌云本土“洞天福地”，溶洞与泉水相融，有摩崖石刻，文化底蕴深厚', 'Lingyun local \"cave paradise\", karst cave and spring water blend, with cliff carvings, profound cultural heritage', '建议游玩1小时，参观溶洞看摩崖石刻，品尝源头泉水，了解本土文化', 'It is recommended to play for 1 hour, visit the cave to see cliff carvings, taste source spring water, and understand local culture', '广西百色市凌云县泗城镇解放社区', 'Jiefang Community, Sicheng Town, Lingyun County, Baise City, Guangxi', 106.5789000000, 24.5890000000, '08:00-17:30', '08:00-17:30', '门票40元/人', 'Ticket 40 yuan/person', '0776-7634567', '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img3.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img3.baidu.com/it/u=345678901,456789012&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (71, '凌云浩坤湖', 'Lingyun Haokun Lake', '凌云本土喀斯特湖泊，湖域狭长，两岸峰林对峙，湖水清澈，有“高山湖泊明珠”之称', 'Lingyun local karst lake, narrow and long lake area, peaks confronting each other on both sides, clear lake water, known as \"pearl of alpine lakes\"', '建议游玩3小时，乘船游湖赏峰林，徒步环湖步道，秋季赏湖光山色', 'It is recommended to play for 3 hours, take a boat tour to enjoy the peak forest, hike the lake loop trail, and enjoy the lakes and mountains in autumn', '广西百色市凌云县伶站瑶族乡浩坤村', 'Haokun Village, Lingzhan Yao Township, Lingyun County, Baise City, Guangxi', 106.7890000000, 24.4567000000, '08:00-18:00', '08:00-18:00', '船票60元/人，免费入园', 'Boat ticket 60 yuan/person, free entry', '0776-7645678', '3小时', '3 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img0.baidu.com/it/u=456789012,567890123&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (72, '凌云泗城古镇', 'Lingyun Sicheng Ancient Town', '凌云本土百年古镇，明清古建筑保存完好，沿澄碧河而建，壮族风情浓郁', 'Lingyun local century-old ancient town, well-preserved ancient buildings of Ming and Qing dynasties, built along the Chengbi River, with strong Zhuang customs', '建议游玩1.5小时，逛古镇看古建筑，沿河岸散步，尝本土特色小吃', 'It is recommended to play for 1.5 hours, walk around the ancient town to see ancient buildings, walk along the river bank, and taste local characteristic snacks', '广西百色市凌云县泗城镇解放街', 'Jiefang Street, Sicheng Town, Lingyun County, Baise City, Guangxi', 106.5890000000, 24.5987000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 3, '民族村寨', 'Ethnic Village', NULL, NULL, 0.0, 0, 0, 0, 'https://img1.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img1.baidu.com/it/u=567890123,678901234&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (73, '凌云茶山古道', 'Lingyun Tea Mountain Ancient Road', '凌云本土千年茶马古道片段，沿茶山蜿蜒，保存完好，可徒步体验茶文化历史', 'A fragment of Lingyun local thousand-year-old tea-horse ancient road, winding along the tea mountain, well-preserved, you can hike to experience the history of tea culture', '建议游玩2小时，徒步古道赏茶山风光，了解茶马古道历史，打卡古驿站', 'It is recommended to play for 2 hours, hike the ancient road to enjoy the tea mountain scenery, understand the history of the tea-horse ancient road, and check in the ancient post station', '广西百色市凌云县加尤镇央里村', 'Yangli Village, Jiayou Town, Lingyun County, Baise City, Guangxi', 106.6987000000, 24.5567000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', 'https://img2.baidu.com/it/u=678901234,789012345&fm=253&fmt=auto&app=138&f=JPEG?w=800&h=500', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (74, '平果通天河景区', 'Pingguo Tongtian River Scenic Area', '国家4A级景区，大型喀斯特地下暗河溶洞，洞内钟乳石千姿百态，暗河游船体验独特', 'National 4A-level scenic area, large-scale karst underground river cave, with various stalactites inside, unique underground river cruise experience', '建议游玩2小时，乘船游览暗河，观赏溶洞奇景，聆听地质讲解', 'It is recommended to play for 2 hours, take a boat tour of the underground river, watch the cave wonders, and listen to geological explanations', '广西百色市平果市黎明乡高桥村', 'Gaoqiao Village, Liming Township, Pingguo City, Baise City, Guangxi', 107.6906000000, 23.3802000000, '08:30-17:30', '08:30-17:30', '门票80元/人，船票40元/人', 'Ticket 80 yuan/person, boat ticket 40 yuan/person', '0776-5826666', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', '4A', '4A', 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic2/27216/20230829182623-1247777229.jpg', 'https://pic.baike.soso.com/ugc/baikepic2/27216/20230829182623-1247777229.jpg,https://pic.baike.soso.com/ugc/baikepic/38626/20240311170922-1991477282.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (75, '平果芦仙湖风景区', 'Pingguo Luxian Lake Scenic Area', '平果市核心滨水休闲景区，湖光山色，植被繁茂，有环湖步道、亲水平台，适合休闲露营', 'The core waterfront leisure scenic area in Pingguo City, with beautiful lakes and mountains, lush vegetation, a lake-circling trail and a water-facing platform, suitable for leisure camping', '建议游玩1.5小时，沿湖徒步，打卡湖心岛，周末可自带装备露营', 'It is recommended to play for 1.5 hours, hike along the lake, check in the lake center island, and bring your own equipment for camping on weekends', '广西百色市平果市新安镇道峨村', 'Daoe Village, Xin\'an Town, Pingguo City, Baise City, Guangxi', 107.5289000000, 23.2978000000, '08:00-18:00', '08:00-18:00', '免费', 'Free', NULL, '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic/32713/20231019154418-1446667827.jpg', 'https://pic.baike.soso.com/ugc/baikepic/32713/20231019154418-1446667827.jpg,https://pic.baike.soso.com/ugc/baikepic/32713/20231019154420-2082277817.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (76, '平果鸳鸯滩漂流景区', 'Pingguo Yuanyang Beach Rafting Scenic Area', '右江支流上的原生态漂流点，河道蜿蜒，水流平缓适中，适合亲子与休闲漂流，周边田园风光好', 'An original ecological rafting spot on the tributary of the Youjiang River, with winding river course and moderate water flow, suitable for parent-child and leisure rafting, with beautiful surrounding pastoral scenery', '建议游玩2小时，体验漂流项目，岸边野餐，夏季避暑佳选', 'It is recommended to play for 2 hours, experience the rafting project, have a picnic by the bank, and it is an excellent choice for summer cooling', '广西百色市平果市马头镇金显村', 'Jinxian Village, Matou Town, Pingguo City, Baise City, Guangxi', 107.5923000000, 23.3289000000, '09:00-17:00（6-9月开放）', '09:00-17:00 (Open June-September)', '漂流门票128元/人', 'Rafting ticket 128 yuan/person', '0776-5888888', '2小时', '2 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic/37898/20240521170123-1329876543.jpg', 'https://pic.baike.soso.com/ugc/baikepic/37898/20240521170123-1329876543.jpg,https://pic.baike.soso.com/ugc/baikepic/37898/20240521170125-1456789012.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (77, '平果铝都文化公园', 'Pingguo Aluminum Capital Cultural Park', '以平果铝工业文化为核心的城市公园，有工业雕塑、文化长廊、市民广场，夜景灯光漂亮', 'An urban park centered on Pingguo aluminum industry culture, with industrial sculptures, cultural corridors, citizen squares, and beautiful night view lights', '建议游玩1小时，白天了解铝都文化，晚上观赏灯光夜景，适合散步休闲', 'It is recommended to play for 1 hour, learn about the aluminum capital culture during the day, watch the light night view at night, and it is suitable for walking and leisure', '广西百色市平果市铝城大道', 'Lvcheng Avenue, Pingguo City, Baise City, Guangxi', 107.5432000000, 23.3456000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic/36789/20240120163422-1890123456.jpg', 'https://pic.baike.soso.com/ugc/baikepic/36789/20240120163422-1890123456.jpg,https://pic.baike.soso.com/ugc/baikepic/36789/20240120163424-1987654321.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (78, '平果邓公山景区', 'Pingguo Denggong Mountain Scenic Area', '平果市地标山体，有登山步道、观景台，可俯瞰平果城区全景，山顶有纪念亭，市民晨练胜地', 'The landmark mountain of Pingguo City, with hiking trails and viewing platforms, you can overlook the entire Pingguo urban area, there is a memorial pavilion on the top, a popular place for citizens to do morning exercises', '建议游玩1小时，登山徒步健身，登观景台看城区全景，清晨观赏日出', 'It is recommended to play for 1 hour, hike for fitness, climb the viewing platform to see the entire urban area, and watch the sunrise in the early morning', '广西百色市平果市马头镇', 'Matou Town, Pingguo City, Baise City, Guangxi', 107.5567000000, 23.3345000000, '全天开放', 'Open all day', '免费', 'Free', NULL, '1小时', '1 hour', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic/39876/20240622153219-2012345678.jpg', 'https://pic.baike.soso.com/ugc/baikepic/39876/20240622153219-2012345678.jpg,https://pic.baike.soso.com/ugc/baikepic/39876/20240622153221-2109876543.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);
INSERT INTO `scenic_spot` VALUES (79, '平果坡造荷花基地', 'Pingguo Pozao Lotus Base', '大型荷花种植基地，每年6-8月荷花盛开，田园风光浓郁，适合摄影打卡、亲子休闲，有荷塘步道', 'A large-scale lotus planting base, lotus blooms from June to August every year, with strong pastoral scenery, suitable for photography, parent-child leisure, and has a lotus pond trail', '建议游玩1.5小时，6-8月最佳观赏期，沿荷塘步道赏花拍照，尝荷花主题小吃', 'It is recommended to play for 1.5 hours, the best viewing period is from June to August, walk along the lotus pond trail to enjoy flowers and take photos, and taste lotus-themed snacks', '广西百色市平果市坡造镇敬村', 'Jing Village, Pozao Town, Pingguo City, Baise City, Guangxi', 107.7234000000, 23.3012000000, '07:00-19:00（花期开放）', '07:00-19:00 (Open during flowering season)', '免费，停车10元/辆', 'Free, parking 10 yuan/vehicle', '0776-5856789', '1.5小时', '1.5 hours', NULL, 2, '自然风光', 'Natural Scenery', NULL, NULL, 0.0, 0, 0, 0, 'https://pic.baike.soso.com/ugc/baikepic/40123/20240712161234-2234567890.jpg', 'https://pic.baike.soso.com/ugc/baikepic/40123/20240712161234-2234567890.jpg,https://pic.baike.soso.com/ugc/baikepic/40123/20240712161236-2345678901.jpg', '2026-03-21 15:17:52', '2026-03-21 15:17:52', NULL);

-- ----------------------------
-- Table structure for score
-- ----------------------------
DROP TABLE IF EXISTS `score`;
CREATE TABLE `score`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '评分ID',
  `user_id` bigint NOT NULL COMMENT '用户ID',
  `target_id` bigint NOT NULL COMMENT '评分目标ID：景点ID/美食ID',
  `target_type` tinyint NOT NULL COMMENT '目标类型：1-景点，2-美食',
  `score` tinyint NOT NULL COMMENT '评分（1-5星）',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_user_target`(`user_id` ASC, `target_id` ASC, `target_type` ASC) USING BTREE COMMENT '同一用户对同一目标仅能评一次',
  INDEX `idx_user_id`(`user_id` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '评分表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of score
-- ----------------------------

-- ----------------------------
-- Table structure for sys_config
-- ----------------------------
DROP TABLE IF EXISTS `sys_config`;
CREATE TABLE `sys_config`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '配置ID',
  `config_key` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置键（如：upload_max_size、comment_audit_switch）',
  `config_value` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置值（如：1024000、true）',
  `config_name` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '配置名称（如：文件上传最大大小、评论审核开关）',
  `config_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT 'string' COMMENT '配置类型（string/int/boolean）',
  `module` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '所属模块（如：系统设置、内容管理）',
  `remark` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '备注',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_config_key`(`config_key` ASC) USING BTREE,
  INDEX `idx_module`(`module` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 1 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统参数配置表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_config
-- ----------------------------

-- ----------------------------
-- Table structure for sys_dict
-- ----------------------------
DROP TABLE IF EXISTS `sys_dict`;
CREATE TABLE `sys_dict`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '字典ID',
  `dict_type` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '字典类型（如：spot_type、food_type、feedback_type）',
  `dict_code` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '字典编码（枚举值）',
  `dict_label_cn` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '字典标签（中文）',
  `dict_label_en` varchar(200) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '字典标签（英文）',
  `sort` int NOT NULL DEFAULT 0 COMMENT '排序值',
  `status` tinyint NOT NULL DEFAULT 1 COMMENT '状态：1-启用 0-禁用',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_dict_type_code`(`dict_type` ASC, `dict_code` ASC) USING BTREE,
  INDEX `idx_dict_type`(`dict_type` ASC) USING BTREE,
  INDEX `idx_status`(`status` ASC) USING BTREE,
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '系统数据字典表（统一管理枚举类）' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of sys_dict
-- ----------------------------

-- ----------------------------
-- Table structure for user_info
-- ----------------------------
DROP TABLE IF EXISTS `user_info`;
CREATE TABLE `user_info`  (
  `id` bigint NOT NULL AUTO_INCREMENT COMMENT '用户ID，主键',
  `wx_openid` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '微信openid，微信登录唯一标识',
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '账号登录的用户名，唯一',
  `password` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL COMMENT '密码，bcrypt加密存储',
  `wx_avatar` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '微信头像地址',
  `wx_nickname` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '微信昵称',
  `nickname` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '自定义昵称',
  `age` tinyint NULL DEFAULT NULL COMMENT '年龄',
  `gender` tinyint NULL DEFAULT 0 COMMENT '性别：0-未知，1-男，2-女',
  `phone` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '联系方式',
  `intro` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NULL DEFAULT NULL COMMENT '个人简介（优化：长度从200扩至500）',
  `login_type` tinyint NOT NULL COMMENT '登录类型：1-微信登录，2-账号密码登录',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  `delete_time` datetime NULL DEFAULT NULL COMMENT '逻辑删除时间（NULL=未删除，非NULL=已删除）',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_username`(`username` ASC) USING BTREE,
  UNIQUE INDEX `uk_wx_openid`(`wx_openid` ASC) USING BTREE,
  INDEX `idx_nickname_phone`(`nickname` ASC, `phone` ASC) USING BTREE COMMENT '昵称/手机号搜索索引',
  INDEX `idx_delete_time`(`delete_time` ASC) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 3 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_unicode_ci COMMENT = '用户信息表' ROW_FORMAT = Dynamic;

